import * as React from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';

import image from "../assets/profile_picture.png";

function About () {
	return (
		<Box
      sx={{
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
				backgroundColor: 'grey',
				gap: 5,
      }}
    >

			<Box
				sx={{
					marginTop: '56px',
					// display: 'flex',
					// flexDirection: 'row',
					// alignItems: 'center',
					// justifyContent: 'center',
					height: '80vh',
					width: '80wh',
					backgroundColor: 'blue'
				}}
			>
				<Box sx={{ height: '50%' }}>
					<Typography component="h1" sx={{ fontSize: '28px', marginBottom: '0px', fontWeight: '300' }}>About Me</Typography>
				</Box>
				<Box sx={{ height: '50%', backgroundColor: 'yellow' }}>
					<Typography component="p" sx={{ fontSize: '16px', marginBottom: '0px', fontWeight: '300' }}>
						Hello, my name is Daria and I live in Switzerland.
					</Typography>
				</Box>
			</Box>

			<Box
				sx={{
					marginTop: '56px',
					// display: 'flex',
					// flexDirection: 'row',
					// alignItems: 'center',
					// justifyContent: 'center',
					height: '80vh',
					width: '80wh',
					backgroundColor: 'blue'
				}}
			>
				{/* <Typography component="h1" sx={{ fontSize: '28px', marginBottom: '0px', fontWeight: '300' }}>Learn More</Typography> */}
				<Box sx={{ height: '50%' }}>
					<Box component='img' src={image} alt='Daria Schumm' sx={{ width: '200px' }}></Box>
				</Box>
				<Box sx={{ height: '50%', backgroundColor: 'yellow' }}></Box>
			</Box>

		</Box>
	)
}

export default About;
